import { writeFile } from "fs/promises";

import { detectLineEnding } from "../internal/detect-line-ending.js";
import { findComponents } from "../library-summary/internal/find-lit-components.js";
import { AUTO_GENERATED_MARKER } from "./constants.js";

/**
 * Removes the legacy auto-generated content from a component file's content.
 *
 * The previous `typesForComponents` generation appended, at the end of each
 * component file, the marker `// ######### Auto generated below #########`
 * followed by a `declare global { … }` block. That content now lives in the
 * `components.ts` file instead, so it must be stripped from the component files.
 *
 * @returns The file content without the auto-generated block (and without the
 *   trailing blank line that preceded the marker), or `null` when the file does
 *   not contain kasstor's auto-generated signature (marker + `declare global`),
 *   so callers can skip writing unchanged files (idempotent).
 */
export const stripAutoGeneratedContent = (fileContent: string): string | null => {
  const lines = fileContent.split(/\r\n|\r|\n/);

  const markerIndex = lines.findIndex(line => line.trim() === AUTO_GENERATED_MARKER.trim());
  if (markerIndex === -1) {
    return null;
  }

  // Only strip kasstor's signature: the marker must be followed (ignoring blank
  // lines) by a `declare global {` block. This avoids touching files that
  // happen to contain the marker followed by unrelated content.
  const nextNonEmptyLine = lines.slice(markerIndex + 1).find(line => line.trim() !== "");
  if (nextNonEmptyLine === undefined || !nextNonEmptyLine.trim().startsWith("declare global")) {
    return null;
  }

  // Keep everything before the marker, dropping the blank line(s) that preceded
  // it, and end the file with a single trailing newline.
  let endIndex = markerIndex;
  while (endIndex > 0 && lines[endIndex - 1].trim() === "") {
    endIndex--;
  }

  const lineEnding = detectLineEnding(fileContent, "\n");

  return lines.slice(0, endIndex).join(lineEnding) + lineEnding;
};

/**
 * Transitional cleanup: removes the legacy auto-generated content (see
 * {@link stripAutoGeneratedContent}) from every processed component file and
 * saves the changed ones.
 *
 * It discovers files with the same `includedPaths`/`excludedPaths` the build
 * uses, so during a dev server (where `includedPaths` is narrowed to the
 * changed files) it only touches those. It is idempotent: files without the
 * auto-generated signature are left untouched and not rewritten.
 *
 * This module is intentionally decoupled and gated by a flag
 * (`fileGeneration.cleanupLegacyComponentTypes`, enabled by default) so it can
 * be turned off in the future without affecting the rest of the build.
 *
 * @returns The absolute paths of the files that were cleaned.
 */
export const cleanupLegacyComponentTypes = async (options: {
  includedPaths: RegExp | RegExp[];
  excludedPaths?: RegExp | RegExp[];
  relativeComponentsSrcPath: string;
}): Promise<string[]> => {
  const { includedPaths, excludedPaths, relativeComponentsSrcPath } = options;

  const files = await findComponents({
    excludedPaths: excludedPaths ?? [],
    includedPaths,
    pattern: relativeComponentsSrcPath
  });

  const cleanedFilePaths: string[] = [];

  await Promise.all(
    files.map(async ({ filePath, fileContent }) => {
      const strippedContent = stripAutoGeneratedContent(fileContent);

      // `null` means there was nothing to strip, so we skip writing (idempotent).
      if (strippedContent === null) {
        return;
      }

      await writeFile(filePath, strippedContent, "utf-8");
      cleanedFilePaths.push(filePath);
    })
  );

  return cleanedFilePaths;
};
